solutions.javascript:
// Solution
var validateEnvironmentVariables = function(composeFile) {
  var pattern = new RegExp('^\${VARIABLE_NAME}_.*|\d+$', 'i');
  var matches = composeFile.services.service1.environment.map(function(envVar) {
    return pattern.test(envVar);
  });
  return matches.filter(function(match) {
    return !match;
  });
}

solutions.python:
class Solution:
    def validateEnvironmentVariables(self, compose_file) -> list:
        pattern = re.compile(r'^\${VARIABLE_NAME}_.*|\d+$', re.IGNORECASE)
        matches = [pattern.match(env_var) for env_var in compose_file['services']['service1']['environment']]
        return [env_var for env_var, match in zip(compose_file['services']['service1']['environment'], matches) if not match]
